from AttribsOutput import *
from AttribsXMLParser import CDebugExecuteTime                                                     # CR.30781; added.
from AttribsXMLParser import CPerfTimer                                                            # CR.30781; added.
import re,string,xml.dom.minidom,sys


def CreateComments(comments):
   if (len(comments)>0):
      comments = string.replace(comments,'*/','  ')
      comments = string.strip(comments)
      return "\n/*\n%s\n*/\n" % (comments,)
   return ''

def EscapeCStringLiteral(s):
   r=s
   r=string.replace(r,'\\','\\\\')
   r=string.replace(r,'\n','\\n')
   r=string.replace(r,'\r','\\r')
   r=string.replace(r,'   ','\   ')
   r=string.replace(r,'"','\\"')
   r=string.replace(r,'\'','\\\'')
   return r
   
def EncodeBufferLiteral(s):
   return '<CBuffer><Size>%d</Size><Data>%s</Data></CBuffer>' % (len(s)/2,s[0:len(s)/2 * 2])

"""
classes = {}            # maps name to: class
class = {}              # {name, descriptive_name, base, filename, code_class_name, comments, typedefs, members, derived_base, subtype, module_id}
typedefs = {}           # maps name to: typedef
typedef = {}            # {name, type, enum, inner_class, derived_class}
enum = []               # list of: {name, value}
inner_class == class
derived_class == class  # makes a copy of another class, sets the name and derived_base, etc. and changes the defaults in members
members = {}            # maps member name to: {name, type, tagname, default, sec_permit_read, sec_permit_write, }
"""

# outputs the c++ version of the derived attribs class header files
#
# SLB 13.jun.2012 CR.15891.V01; Added support for Aliased string type... FolderName.
# SLB 08.mar.2013 CR.15891.V03; Added support for Aliased string type... FileName
# SLB 03.apr.2013 CR.15891.V03; Reformatted type_map and type_map_underlying code.
# SLB 04.apr.2013 CR.15891.V04; Added support for many more Aliased string 
# types... PclMetaDrive - DbsMonitor
# SLB 09.apr.2013 CR.15891.V04; Added support for Aliased string AliasAfpdsSharedResource
# SLB 12.apr.2013 CR.15891.V04; corrected misspelling of 'SpdAttribs::CStreamableAliasableDbsCheckpointObj'
# SLB 04.aug.2015 CR.19280; Fleshed out support of encrypted members. Renamed type to work with
# C++ base code.
# SLB 23.sep.2021 CR.30781; Major changes maded. In general, it tries to adhere to the C++ 
# concepts of scope now. e.g. types defined in a base class should be accessible to the 
# derived class.
# All top level classes are considered "global"... So they are in the "scope" of any other top 
# class or subclass thereof. 
# cpp output has the following enhancements:
# 1) Any class or type defined in a base class is now supported directly in the derived class.
# 2) Any global/top level class can be referenced by another class directly. It no longer needs  
#    to define a "derived" class with the global class as the base class.
# 3) All SetXXX/GetXXX/ClearXXX methods are virtual now... And can be over-ridden by derived classes.
# 4) Derived classes can declare new members.
# 5) Derived classes can over-ride defaults of base class members (simple types only) (This is the 
#    feature needed to fix this CR).
#
class AttribsOutputCPP(AttribsOutput):
   def __init__(self):
      AttribsOutput.__init__(self)

      self.simple_type_list = {
         'string',
         'xmlstring',
         'encrypted',
         'unsigned __int64',
         'unsigned __int32',
         'unsigned __int16',
         'unsigned __int8',
         '__int64',
         '__int32',
         '__int16',
         '__int8',
         'bool',
         'time_t',
         'size_t',
         'float',
         'double',
         'DateTime',
         #'QUADWORD', 
         #'DWORD', 
         #'WORD', 
         #'BYTE',
         #'std::wstring',
         }
      
      self.resource_type_list = {
         'AliasFolder',
         'AliasFile',
         'AliasPclMetaDriver',
         'AliasPclMetaMedia',
         'AliasPclMetaOutput',
         'AliasAfpdsSharedResource',
         'AliasRje3211Fcb',
         'AliasMachineName', 
         'AliasDbsCheckpoint', 
         'AliasDbsMonitor'
         }

      self.type_map = {
         #'string': 'std::wstring', 
         'string': 'CSpdCString', 
         'xmlstring': 'CSpdCString', 
         #'encrypted': 'SpdAttribs4::CAttributeCryptoString', 
         'encrypted': 'wstring_crypto',
         'unsigned __int64': 'QUADWORD', 
         'unsigned __int32': 'DWORD', 
         'unsigned __int16': 'WORD', 
         'unsigned __int8': 'BYTE', 
         '__int64': '__int64',  
         '__int32': '__int32', 
         '__int16': '__int16', 
         '__int8': 'char', 
         'bool': 'bool', 
         'time_t': '__time64_t', 
         'size_t': 'size_t', 
         'float': 'float', 
         'double': 'double', 
         'byte[]': 'SpdAttribs4::CAttributeCBuffer', 
         'DateTime': 'FILETIME', 
         'AliasFolder' : 'SpdAttribs4::CStreamableResFolderName', 
         'AliasFile' : 'SpdAttribs4::CStreamableResFileName',
         'AliasPclMetaDriver' : 'SpdAttribs4::CStreamableResPclMetaDriver',                        # CR.15891.V04; added.
         'AliasPclMetaMedia' : 'SpdAttribs4::CStreamableResPclMetaMedia',                          # CR.15891.V04; added.
         'AliasPclMetaOutput' : 'SpdAttribs4::CStreamableResPclMetaOutput',                        # CR.15891.V04; added.
         'AliasAfpdsSharedResource' : 'SpdAttribs4::CStreamableResAfpdsSharedResource',            # CR.15891.V04; added.
         'AliasRje3211Fcb' : 'SpdAttribs4::CStreamableResRje3211Fcb',                              # CR.15891.V04; added.
         'AliasMachineName' : 'SpdAttribs4::CStreamableResMachineName',                            # CR.15891.V04; added.
         'AliasDbsCheckpoint' : 'SpdAttribs4::CStreamableResDbsCheckPoint',                        # CR.15891.V04; added.
         'AliasDbsMonitor' : 'SpdAttribs4::CStreamableResDbsMonitor'                               # CR.15891.V04; added.
         }

      self.type_map_underlying = {
			'byte[]' : "CBuffer"
			}
      #
      # this map is used by methods which generate Aliasable Resource initializing code.
      #
      self.aliased_resource_parm_map = {                                                           # CR.15891.V04; added.
         'res_pkg_options_desired' : ['SetPackageOptionsDesired', 'TPackageOptionsDesired'],
         'res_validation_options' : ['SetValidationOptions', 'TValidationOptions'],
         'res_runtime_options' : ['SetRuntimeOptions', 'TRuntimeOptions']
         }
   
         
   
   def ProcessXML(self, class_list):
      # for each attribs class
      for attribs_class in class_list.values():
         self.GenerateGenericAttribsFile(attribs_class)
   #
   # SLB 21.jul.2015 CR.18952; attribs description is passed into constructor.
   # SLB 09.may.2016 CR.21547; Fixes to make sure that defaults get used for byte[] members.
   # SLB 09.may.2016 CR.21553; Fixes to make sure that resource descriptions are populated 
   # SLB 22.mar.2017 CR.23181; For collection types, legacy xml is no longer always on. It is the
   # default, except when the collection is in "slim mode".
   # SLB 23.sep.2021 CR.30781; Changes to allow initializers to be generated for derived classes.
   #
   def GenerateMemberInitializer(self, member_info, default_value_override = None):
      # CR.30781; Commented out code which exists immediately if this is an "inherited" member.
      #if (member_info['inherited'] == True):
      #   return ""
      class_text = ''
      if (not default_value_override):
         default_value_override = member_info['default']
      
      # SLB 23.sep.2021 Query: Why does this method use typedef_type and type_underlying 
      # exclusively, while other areas of the code use 'type' ... unless 'type' is not 
      # part of member_info.
      # attribs class member variables need to use the alternate copy constructor syntax
      underlying_type = member_info['type_underlying']
      typedef_type = member_info['typedef_type']
      if (typedef_type == 'class'):
         class_text += "%s(L\"%s\", false)" % (member_info['name'], member_info['tagname'])
      elif (typedef_type == 'derived'):
         class_text += "%s(L\"%s\", false)" % (member_info['name'], member_info['tagname'])
      elif (underlying_type == 'byte[]'): 
         class_text += "%s(L\"%s\", false, true, L\"%s\")" % (member_info['name'], member_info['tagname'], member_info['default'])              # CR.21547; modified.
      elif (typedef_type == 'collection'):
         is_slim = 'false'
         is_legacy_xml = 'true'                                                                                                                 # CR.23181; added.
         collection_type = member_info['collection_info']['type']
         if (collection_type=='SlimList' or collection_type=='SlimMap'):
            is_slim = 'true'
            is_legacy_xml = 'false'                                                                                                             # CR.23181; added.
         class_text += "%s(L\"%s\", false, %s, %s)" % (member_info['name'], member_info['tagname'], is_legacy_xml, is_slim)                     # CR.23181; modified.
      elif (underlying_type in self.resource_type_list):
         class_text += "%s(L\"%s\", false, true, L\"%s\")" % (member_info['name'], member_info['tagname'], member_info['description'])          # CR.21553; modified.
      else:
         pass 
      return class_text
   
   # SLB 23.sep.2021 CR.30781; Added use of CPerfTimer to trap any extrodinary timing issues and
   #  generate a warning message.
   def GenerateGetSetInterfaceMethods(self, interface_info):
      # CR.30781; initialize a timer to track code execution time.
      timer = CPerfTimer('GenerateGetSetInterfaceMethods', '')                                     # CR.30781; added.

      if (interface_info['type'] == 'CSpdCString'): 
         t_typebase = "CSpdCString"
         t_type = "CSpdCString"
      else:
         t_type = interface_info['type_underlying']
         if (t_type in self.type_map):
            t_type = self.type_map[interface_info['type_underlying']]
         t_typebase = t_type
      member_text =  "\n"
      member_text += "\n   virtual TPropertyResult<%s> Get%s() const = 0; " % (t_type, interface_info['name'])
      member_text += "\n   virtual void Set%s(const %s &val) = 0;" % (interface_info['name'], t_typebase)

      timer.complete()                                                                             # CR.30781; added.
      return member_text


   #
   # Generate GetXXX() and SetXXX() for the given member.
   # SLB 06.apr.2016 CR.18552.V04; Added seperate support for FILETIME type. No default value is supported (nor needed).
   # SLB 09.may.2016 CR.21547; Fixes so that defaults are set appropriately for all GetXXX() methods. Also, modified how double 
   # code is generated (mimics wstring_crypto now)
   # SLB 05.jun.2019 CR.27900; Added new member method: ClearXXX().
   # SLB 03.sep.2021 CR.30781; Allow derived attribs classes to specify a different default for a member.
   # Also, allows derived classes to define additional members.
   #
   def GenerateGetSetMethods(self, member_info):

      # CR.30781; comment out code which exits immediately if this is a derived class.
      #if (member_info['inherited'] == True):                                                                                                   # CR.30781; commented.
      #   return ""                                                                                                                             # CR.30781; commented.
      val_type = "QUADWORD"
      member_text =  "\n"
      prResDefault = ""                                                                                                                         # CR.21547; added.
      if (len(member_info['default'])):                                                                                                         # CR.21547; added.
         prResDefault = "(%s, false)" % (member_info['default'])                                                                                # CR.21547; added.

      # CR.30781; for all SetXXXX(), GetXXXX() methods generated below, add key word virtual
      if (member_info['type'] == 'FILETIME'): 
         t_typebase = member_info['type']
         t_type = "FILETIME"
         prResInit1 = ""                                                                                                                        # CR.21547; added.
         if (len(member_info['default'])):                                                                                                      # CR.21547; added.
            prResInit1 = "\n      FILETIME def = %s; " % member_info['default']                                                                 # CR.21547; added.
            prResDefault = "(def, false)"                                                                                                       # CR.21547; added.
         member_text += "\n   virtual TPropertyResult<%s> Get%s() const " % (t_type, member_info['name'])                                       # CR.30781; modified.
         member_text += "\n   { "
         member_text += prResInit1                                                                                                              # CR.21547; added.
         member_text += "\n      TPropertyResult<%s> prRes%s;" % (t_type, prResDefault)                                                         # CR.21547; modified.
         member_text += "\n      prRes.m_bIsModified = GetMember(L\"%s\", prRes.m_tVal); " % (member_info['tagname'])
         member_text += "\n      return prRes;"
         member_text += "\n   }"
         member_text += "\n   virtual void Set%s(const %s &val) { SetMember(L\"%s\", val); }" % (member_info['name'], t_type, member_info['tagname']) # CR.30781; modified.
      elif (member_info['type'] == 'wstring_crypto' or member_info['type'] == 'double'):                                                        # CR.21547; modified.
         t_type = member_info['type']
         member_text += "\n   virtual TPropertyResult<%s> Get%s() const " % (t_type, member_info['name'])                                       # CR.30781; modified.
         member_text += "\n   { "
         member_text += "\n      TPropertyResult<%s> prRes%s;" % (t_type, prResDefault)                                                         # CR.21547; modified.
         member_text += "\n      prRes.m_bIsModified = GetMember(L\"%s\", prRes.m_tVal); " % (member_info['tagname'])
         member_text += "\n      return prRes;"
         member_text += "\n   }"
         member_text += "\n   virtual void Set%s(const %s &val) { SetMember(L\"%s\", val); }" % (member_info['name'], t_type, member_info['tagname']) # CR.30781; modified.

      elif (member_info['type'] == 'CSpdCString'): 
         t_typebase = member_info['type']
         t_type = "CSpdCString"
         is_xml = "false"
         if (member_info['type_underlying']=='xmlstring'):
            is_xml = "true"
         member_text += "\n   virtual TPropertyResult<%s> Get%s() const " % (t_type, member_info['name'])                                       # CR.30781; modified.
         member_text += "\n   { "
         member_text += "\n      TPropertyResult<%s> prRes%s;" % (t_type, prResDefault)                                                         # CR.21547; modified.
         member_text += "\n      prRes.m_bIsModified = GetMember(L\"%s\", prRes.m_tVal, %s); " % (member_info['tagname'], is_xml)
         member_text += "\n      return prRes;"
         member_text += "\n   }"
         member_text += "\n   virtual void Set%s(const %s &val) { SetMember(L\"%s\", val, %s); }" % (member_info['name'], t_type, member_info['tagname'], is_xml) # CR.30781; modified.
      else:
         t_type = member_info['type_underlying']
         stream_in_decimal = "false"
         if (member_info['numencoding'] == 'decimal'):
            stream_in_decimal = "true"
         if (t_type in self.type_map):
            t_type = self.type_map[member_info['type_underlying']]
         member_text += "\n   virtual TPropertyResult<%s> Get%s() const " % (t_type, member_info['name'])                                       # CR.30781; modified.
         member_text += "\n   { "
         member_text += "\n      TPropertyResult<%s> prRes(%s, false) ; %s val(0); " % (t_type, member_info['default'], val_type)
         member_text += "\n      prRes.m_bIsModified = GetMember(L\"%s\", val, %s); " % (member_info['tagname'], stream_in_decimal)
         if (member_info['type_underlying']=='bool'):
            member_text += "\n      if (prRes.m_bIsModified) prRes.m_tVal = val!=0; " 
         else:
            member_text += "\n      if (prRes.m_bIsModified) prRes.m_tVal = (%s)val; " % (t_type)
         member_text += "\n      return prRes;"
         member_text += "\n   }"
         member_text += "\n   virtual void Set%s(const %s &val) { SetMember(L\"%s\", (QUADWORD)val, %s); }" % (member_info['name'], t_type, member_info['tagname'], stream_in_decimal) # CR.30781; modified.
      # Add ClearXXX() method.
      member_text +=    "\n   virtual void Clear%s() { ClearMember(L\"%s\"); }" % (member_info['name'], member_info['tagname'])                 # CR.30781; modified. CR.27900; added.

      return member_text
      

   #
   # Generate cpp code for an entire attribs class. 
   #
   # SLB 17.apr.2013 CR.15891.V04; Pretty significant changes to this code. Now generates classes that are structured as
   # follows:
   #  type definitions (includes sub-classes)
   #  member variable declarations
   #  constructors
   #  assignment operators
   #  static methods
   #  all other methods
   # Also, now geneartes comment headers for all constructors and assignment operators.
   # Certain constructors now generate calls to initialize aliasable resource custom settings. This shows
   # up as a call to GenerateClassAliasedResourceInitializers()
   # SLB 21.jul.2015 CR.18952; attribs description is now passed into non-class constructors.
   # SLB 13.sep.2018 CR.18557; Fixed output to support collections of enum types.
   # SLB 20.sep.2018 CR.18557.V01; Add support for disabling Cpp compiler warnings, if desired.
   # SLB 28.nov.2018 CR.7698; Changes to better support base_class from an 'outer' class type.
   # SLB 24.sep.2021 CR.30781; Simplified initialization of base_class_xxx variable at top of 
   # method, now that input format for derived classes is consistent between top-level classes 
   # and typedef classes.
   # Added some timer checks to catch issues with script taking longer than expected to execute.
   #
   def GenerateAttribsClass(self, attribs_class, inner_class, derived_class):
      # enable timer for debugging script.
      #timer = CDebugExecuteTime('CPP GenerateAttribsClass', attribs_class['code_class_name'], True)

      # CR.30781; Format for top level derived classes and "typedef" derived classes has been
      # normalized so no distinct handling required for 'derived' classes (AttribsClassDerived).
      # CR.7698; Determine base_class_name and other basic values for the c++ class.
      # Note of caution. all "name" variables here actually represent the code names... not
      # the attribs class name (most of the time these are the same... but not always)
      class_name = attribs_class['code_class_name']
      base_class_name = attribs_class['base_class_code_name']
      base_class_name_full = base_class_name
      base_class_type = 'public'

      # if no base_class_name specified, then must use the c++ attribs base class.
      if len(base_class_name) == 0:
         base_class_name='CAttributes'
         base_class_name_full = 'SpdAttribs4::%s' % base_class_name
      elif len(attribs_class['base_class_type']):
         base_class_type = attribs_class['base_class_type']

      #
      # Ready to start generating class_text
      #
      class_text = ""
      cpp_pragmas_end = ""                                                                         # CR.18557.V01; added
      if (not derived_class and len(attribs_class['cpp_pragma_disable_warnings'])!=0) :            # CR.18557.V01; added if():
         cpp_pragma_disable_warnings = attribs_class['cpp_pragma_disable_warnings']
         class_text += "\n#pragma warning (push)"
         class_text += "\n#pragma warning ( disable : %s )" % (cpp_pragma_disable_warnings)
         cpp_pragmas_end += "\n#pragma warning (pop)\n"

      #
      # Add xml specified comment code
      #
      class_text += CreateComments(attribs_class['comments'])
      #
      # Add class declaration header
      #
      cpp_linkage = ""
      if (len(attribs_class['cpp_linkage'])!=0) :
         cpp_linkage = attribs_class['cpp_linkage']

      class_text += "\nclass %s %s " %  (cpp_linkage, class_name)                                  # CR.7698; modified.
      class_text += ":\n   %s %s" % (base_class_type, base_class_name_full)                        # CR.7698; modified.
      class_text += "\n{"
      class_text += "\npublic:"  
      #     
      # declare typedefs (nested attribs classes and enums) and collect them for use later
      #
      x = OutputOrderDictionaryValues(attribs_class['typedefs'])                                   # CR.30781; added.
      if (len(x)):
         timer2 = CPerfTimer('Generating type definitions', class_name)                            # CR.30781; added.
         typedefs = ''
         for typedef in x:                                                                         # CR.30781; modified.
            typedefs += self.GenerateTypedef(typedef, attribs_class['predefined_types'])           # CR.18557; modified.
         class_text += IndentTextTabs(typedefs,1)
         class_text += "   \n"
         timer2.complete()                                                                         # CR.30781; added.

		#
      # Add EnumToString() methods which translate an enum val to its alias string.
      #
      enum_to_string_text = ''
      for typedef in OutputOrderDictionaryValues(attribs_class['typedefs']):
         enum_to_string_text += self.GenerateEnumToStringMethods(typedef)
      if (len(enum_to_string_text)):
         class_text += "\n   //"
         class_text += "\n   // EnumToString() methods."
         class_text += "\n   //"
         class_text  += IndentTextTabs(enum_to_string_text,1)
         class_text += "   \n"

      ######################################
      # member declarations/access methods #
      ######################################
      member_declaration_text = ''
      member_accessmethod_text = ''
      #
      # implement GetXXX/SetXXX() methods for interface methods from base class.
      #
      x = OutputOrderDictionaryValues(attribs_class['interfaces'])
      bIsAbstract = False                                                                          # CR.17482; added.
      if (len(x)):
         timer2 = CPerfTimer('Generating pure virtual interface methods', class_name)              # CR.30781; added.
         # there are interface methods defined for this class. All interface methods are pure-virtual,
         # so set bAbstract to True.
         bIsAbstract = True                                                                        # CR.17482; added.
         member_accessmethod_text += "\n   //"
         member_accessmethod_text += "\n   // Pure virtual SetXXX/GetXXX() access methods. Must be defined by derived class."
         member_accessmethod_text += "\n   //"
         for interface in x: 
            interace_info = self.ComputeInterfaceInfo(attribs_class,interface)
            member_accessmethod_text += self.GenerateGetSetInterfaceMethods(interace_info)
         timer2.complete()                                                                         # CR.30781; added.
      #
      # implement GetXXX/SetXXX() methods for pure virtual methods defined by base class.
      #
      x = OutputOrderDictionaryValues(attribs_class['base_class_interfaces'])
      if (len(x)):
         timer2 = CPerfTimer('Generating derived interface methods', class_name)
         member_accessmethod_text += "\n   //"
         member_accessmethod_text += "\n   // Definition of base class Pure virtual SetXXX/GetXXX() access methods."
         member_accessmethod_text += "\n   //"
         for base_interface in x:
            base_interface_info = self.ComputeMemberInfo(attribs_class, base_interface)
            member_accessmethod_text += self.GenerateGetSetMethods(base_interface_info)
         timer2.complete()
      #
      # implement GetXXX/SetXXX() methods for class members.
      #
      x = OutputOrderDictionaryValues(attribs_class['members'])
      if (len(x)):
         timer2 = CPerfTimer('Generating GetSetMethods', class_name)                               # CR.30781; added.

         member_accessmethod_text += "\n   //"
         member_accessmethod_text += "\n   // Definition of SetXXX/GetXXX() access methods specific to this class (%s)."  % (attribs_class['name'])
         member_accessmethod_text += "\n   //"
         for member in x:
            member_info = self.ComputeMemberInfo(attribs_class, member)

            # CR.30781; again, removed code which would skip "inherited" members.
            if (member_info['type_underlying'] in self.simple_type_list or member_info['typedef_type'] == 'enum' ):
               member_accessmethod_text += self.GenerateGetSetMethods(member_info)
            else:
               member_declaration_text += '   %s %s;\n' % (member_info['type'], member_info['name'])
         timer2.complete()                                                                         # CR.30781; added.

      #
      # Note: though member access methods were just calculated, they are not added to
      # output until after the class initializers (constructors and operator = ())
      #
      class_text += member_declaration_text
      #
      # if no members defined and no base class, then this is most likely an interface class.
      # 
      if (len(attribs_class['members']) == 0 and len(base_class_name) == 0 and not derived_class and attribs_class['interfaces']): # CR.7698; modified.
         class_text += member_accessmethod_text
         #
         # end of the class
         #
         class_text += '\n};\n'
         return class_text
         
      ################
      # Constructors #
      ################
      
      # this class does not derive off of other attributes classes. 
      # It does not need to initialize base class attribs members via constructors
      #
      if (not derived_class):
         timer2 = CPerfTimer('Generating constructors', class_name)                                # CR.30781; added.
         #
         # default constructor
         #
         class_text += "\n"
         class_text += "\n   /* Default constructor (stand alone) - not derived."
         class_text += "\n    *-------------------------------------------------------------------------------*/"
